targets.query:
// CPU 사용률 계산
// node_cpu_seconds_total 은 모드별 누적 초 단위 카운터
// derivative() 로 초당 변화율 계산 후 idle 을 제외한 비율 산출
//
// 계산 순서:
// 1. idle 모드 비율 계산
// 2. 100 - idle% = 사용률
idle = from(bucket: v.bucket)
  |> range(start: -5m)
  |> filter(fn: (r) => r._measurement == "eve_ng_node_cpu_seconds_total")
  |> filter(fn: (r) => r.mode == "idle")
  |> derivative(unit: 1s, nonNegative: true)
  |> mean()
  |> map(fn: (r) => ({ r with _value: r._value * 100.0 }))

total = from(bucket: v.bucket)
  |> range(start: -5m)
  |> filter(fn: (r) => r._measurement == "eve_ng_node_cpu_seconds_total")
  |> derivative(unit: 1s, nonNegative: true)
  |> mean()
  |> group()
  |> sum()

join(
  tables: {idle: idle, total: total},
  on: ["_time"]
)
|> map(fn: (r) => ({ r with _value: 100.0 - (r._value_idle / r._value_total * 100.0) }))

// 업타임 계산
// 현재 Unix 타임스탬프(초) - boot_time(초) = 업타임(초)
from(bucket: v.bucket)
  |> range(start: -5m)
  |> filter(fn: (r) => r._measurement == "eve_ng_node_boot_time_seconds")
  |> last()
  |> map(fn: (r) => ({
       r with
       _value: float(v: uint(v: now())) / 1000000000.0 - r._value
     }))

// CPU 모드별 사용률 시계열
// idle 제외 주요 모드(user/system/iowait/softirq)만 표시
// derivative() 로 초당 변화율 계산 후 비율(%) 변환
from(bucket: v.bucket)
  |> range(start: v.timeRangeStart, stop: v.timeRangeStop)
  |> filter(fn: (r) => r._measurement == "eve_ng_node_cpu_seconds_total")
  |> filter(fn: (r) => r.mode == "user" or r.mode == "system" or r.mode == "iowait" or r.mode == "softirq")
  |> derivative(unit: 1s, nonNegative: true)
  |> map(fn: (r) => ({ r with _value: r._value * 100.0 }))
  |> group(columns: ["mode"])
  |> aggregateWindow(every: v.windowPeriod, fn: mean)
  |> pivot(
       rowKey: ["_time"],
       columnKey: ["mode"],
       valueColumn: "_value"
     )
